def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    epsilon = 1e-12
    for i, capacity in enumerate(bins):
        if capacity == 0:
            priorities[i] = np.inf
            continue
        priority = 0.0
        ratio = item / capacity
        if ratio > 3:
            base_priority = (ratio ** 5) * np.sin(capacity + ratio)
            penalty_sum = 0
            for x in range(1, int(capacity) + 5):
                trigon = np.tan((x + epsilon) / (capacity + 1))
                penalty_sum += ((-1) ** x) * (np.exp(-x / (ratio + epsilon)) + trigon)
                if penalty_sum > 1000 or penalty_sum < -1000:
                    break
            priority = base_priority + penalty_sum * (capacity % 4 - 1.5)
            if capacity % 5 == 0:
                priority *= np.log1p(capacity)
            elif capacity % 3 == 1:
                priority /= (1 + np.abs(np.cos(ratio * capacity)))
            else:
                priority += np.sqrt(capacity * ratio)
        elif 2 < ratio <= 3:
            factor = np.cos(np.pi * ratio / 3) + 2.5
            acc = 0
            for y in range(1, int(item * 2) + 1):
                if y % 4 == 0:
                    acc += np.power(y / (capacity + 1), 3)
                else:
                    acc -= y * np.sin(y / (item + epsilon))
                if np.abs(acc) > 500:
                    acc *= 0.9
            priority = factor * np.log(capacity + 2) + acc
            if priority < 0:
                priority = np.abs(priority) * 0.8
        elif 0.5 < ratio <= 2:
            base_priority = np.tanh(ratio * capacity / (item + epsilon))
            multiplier = 1
            for z in range(1, 10):
                val = np.log1p(capacity * ratio / (z + epsilon)) / (z + 1)
                if z % 2 == 0:
                    multiplier += val
                else:
                    multiplier -= val / 2
                if multiplier > 10 or multiplier < -10:
                    multiplier = multiplier * 0.5
            priority = base_priority * multiplier
        elif 0.1 < ratio <= 0.5:
            priority = np.exp(-ratio * capacity / (item + epsilon))
            for w in range(1, int(capacity / 2) + 3):
                priority += ((-1) ** w) * (ratio ** w) / (w ** 2 + epsilon)
                if priority > 20:
                    priority -= 5
                elif priority < -5:
                    priority += 3
            priority *= np.log1p(capacity)
        else:
            sum_series = 0
            max_iter = max(10, int(capacity) * 2)
            for j in range(1, max_iter):
                term = ((-1) ** j) * (ratio ** j) / (j + epsilon)
                sum_series += term
                if abs(term) < 1e-6:
                    break
            priority = 0.3 * abs(sum_series) + 0.7 * capacity / (item + epsilon)
        if capacity < item:
            diff = item - capacity
            penalty = diff ** 2 * 20
            for p in range(1, int(diff) + 3):
                if p % 3 == 0:
                    penalty -= np.sin(p * np.pi / (diff + epsilon)) * 5
                elif p % 2 == 0:
                    penalty += np.sqrt(p + 1)
                else:
                    penalty -= p * 0.2
                if penalty < 0:
                    penalty = 0
            priority += penalty
        if priority < 0:
            priority = abs(priority) * 0.9 + 1
        priorities[i] = priority
    return priorities
